  ('social-worker-moex-05615', 'social-worker', 'social-worker-moex-105-0e79f916', 'sub-social-worker-01', NULL, 'essay', '照顧是一份愛的勞動，雖然失能老人主要家庭照顧者可以從過程中獲得一些正向回
饋，但是長期且繁重的照顧工作對主要照顧者而言，仍是沉重的負荷。試說明此沉
重的照顧負荷對失能老人主要家庭照顧者可能引發的負面影響為何？並且進一步
說明他們所需要的協助。（25分）', '[]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:31+00:00", "source_pdf_sha1": "622d8515d2b0", "answer_pdf_sha1": null, "source_family": "moex-gov-tw", "moex": {"exam_code": "105090", "c": "107", "s": "0605", "q": "1"}, "raw_section_label": "甲、申論題部分", "subject": "人類行為與社會環境", "year": "105", "exam_name": "105年第二次中醫師分階段營養師心理師護理師社工師暨法醫師語言治療師聽力師牙體技術師考試", "original_question_number": "一", "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-05616', 'social-worker', 'social-worker-moex-105-0e79f916', 'sub-social-worker-01', NULL, 'essay', '「家庭」，應該提供兒童少年成長過程中必要之保護與協助，但是兒童少年來自家
庭的虐待事件仍不斷發生。試說明造成家庭中兒童少年虐待事件發生的可能原因為
何？以及受虐事件對兒童少年可能造成的影響為何？（25分）', '[]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:31+00:00", "source_pdf_sha1": "622d8515d2b0", "answer_pdf_sha1": null, "source_family": "moex-gov-tw", "moex": {"exam_code": "105090", "c": "107", "s": "0605", "q": "1"}, "raw_section_label": "甲、申論題部分", "subject": "人類行為與社會環境", "year": "105", "exam_name": "105年第二次中醫師分階段營養師心理師護理師社工師暨法醫師語言治療師聽力師牙體技術師考試", "original_question_number": "二", "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-05617', 'social-worker', 'social-worker-moex-105-0e79f916', 'sub-social-worker-01', NULL, 'single_choice', '人們會隨著生命週期的不同而有所改變是一個不爭的事實，有關生命週期觀點，下列敘述何者最貼切？', '["人的特質或行為的發展是循著一定的階段發展，以致人格具延續性和累積性", "人擁有自由選擇的能力和天性，個人具有自主性或自我抉擇，所選擇的可以脫離人格特質或過去經驗", "改變在人的一生當中不斷的發生，以致人格必須具備一定的穩定性來因應變動", "由於發展階段是固定的，因此個體因應環境的刺激而做固定的反應"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:31+00:00", "source_pdf_sha1": "622d8515d2b0", "answer_pdf_sha1": "c363cc051cc1", "source_family": "moex-gov-tw", "moex": {"exam_code": "105090", "c": "107", "s": "0605", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "人類行為與社會環境", "year": "105", "exam_name": "105年第二次中醫師分階段營養師心理師護理師社工師暨法醫師語言治療師聽力師牙體技術師考試", "original_question_number": 1, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-05618', 'social-worker', 'social-worker-moex-105-0e79f916', 'sub-social-worker-01', NULL, 'single_choice', '對於「記憶」的描述，下列何者不恰當？', '["長期記憶能將訊息保存數天、數月或數年之久，訊息的容量也具有無限的可能", "情節記憶是有關生活中清楚的、明確的、經驗的記憶，又稱為明確記憶", "老年會伴隨著心理功能的衰退，無法鞏固長期記憶的資料", "社工人員詢問服務對象總統是誰，是想評估複誦記憶"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:31+00:00", "source_pdf_sha1": "622d8515d2b0", "answer_pdf_sha1": "c363cc051cc1", "source_family": "moex-gov-tw", "moex": {"exam_code": "105090", "c": "107", "s": "0605", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "人類行為與社會環境", "year": "105", "exam_name": "105年第二次中醫師分階段營養師心理師護理師社工師暨法醫師語言治療師聽力師牙體技術師考試", "original_question_number": 2, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-05619', 'social-worker', 'social-worker-moex-105-0e79f916', 'sub-social-worker-01', NULL, 'single_choice', 'William Glasser（1998）指出人類被五種與生俱來的基本需求所驅使，其順序由左至右排列，下列何者正確？', '["生存、愛與歸屬感、自由、權力、快樂", "生存、愛與歸屬感、權力、自由、快樂", "生存、愛與歸屬感、權力、快樂、自由", "生存、快樂、愛與歸屬感、權力、自由"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:31+00:00", "source_pdf_sha1": "622d8515d2b0", "answer_pdf_sha1": "c363cc051cc1", "source_family": "moex-gov-tw", "moex": {"exam_code": "105090", "c": "107", "s": "0605", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "人類行為與社會環境", "year": "105", "exam_name": "105年第二次中醫師分階段營養師心理師護理師社工師暨法醫師語言治療師聽力師牙體技術師考試", "original_question_number": 3, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL)
